import _pickle as cPickle
import base64

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded = base64.b64decode(token_str)
    except (TypeError, ValueError):
        return None
    try:
        token_obj = cPickle.loads(decoded)
    except (cPickle.UnpicklingError, EOFError, cPickle.PickleError):
        return None
    return token_obj
